SELECT bsp_name
FROM bulk_supply_points
WHERE capacity > 500;

SELECT SUM(capacity) AS total_operational_capacity
FROM bulk_supply_points
WHERE status = 'operational';

SELECT bsp_name
FROM bulk_supply_points
ORDER BY bsp_name;

SELECT MAX(capacity) AS max_capacity
FROM bulk_supply_points
WHERE status = 'active';

SELECT bsp_name
FROM bulk_supply_points
ORDER BY bsp_name ASC;

SELECT scenario_name
FROM scenarios
ORDER BY scenario_name;

SELECT bsp_name, status, capacity
FROM bulk_supply_points
ORDER BY capacity DESC;

SELECT bsp_name, latitude, longitude
FROM bulk_supply_points
WHERE capacity > 100;

SELECT scenario_name
FROM scenarios
WHERE scenario_id = 1;
